[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    [DataRow("Doe", "John", "Doe, John", DisplayName = "Standard names")]
    [DataRow("Smith", "Jane", "Smith, Jane", DisplayName = "Another standard name")]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
    public void FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
    {
        // Arrange
        var student = new Student { LastName = lastName, FirstMidName = firstName };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FullName_InstructorInheritsFromPerson_ReturnsCorrectFormat()
    {
        // Arrange
        var instructor = new Instructor { LastName = "Anderson", FirstMidName = "Thomas" };

        // Act
        var result = instructor.FullName;

        // Assert
        Assert.AreEqual("Anderson, Thomas", result);
    }

