using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly_ExactDivision()
    {
        // Arrange
        var source = Enumerable.Range(1, 30).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly_WithRemainder()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_SinglePage_WhenFewerItemsThanPageSize()
    {
        // Arrange
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(1, result.TotalPages);
    }

    [TestMethod]
    public void PageIndex_StoredCorrectly()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

        // Assert
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 5, pageSize: 10);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Constructor_SetsPropertiesCorrectly()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, count: 30, pageIndex: 2, pageSize: 10);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual("a", result[0]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from other tests (static queue)
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _service?.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Course", "42", EntityOperation.UPDATE, "System");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.IsTrue(notification.Message.Contains("Course (ID: 42)"));
    }

    [TestMethod]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Department 'Engineering' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Instructor", "3", "Jane Doe", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Instructor 'Jane Doe' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdFormat()
    {
        // Arrange & Act
        _service.SendNotification("Student", "99", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DefaultUserName_IsSystem()
    {
        // Arrange & Act
        _service.SendNotification("Course", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleSends_ReturnsFIFOOrder()
    {
        // Arrange
        _service.SendNotification("First", "1", EntityOperation.CREATE);
        _service.SendNotification("Second", "2", EntityOperation.UPDATE);
        _service.SendNotification("Third", "3", EntityOperation.DELETE);

        // Act & Assert
        var first = _service.ReceiveNotification();
        Assert.AreEqual("First", first.EntityType);

        var second = _service.ReceiveNotification();
        Assert.AreEqual("Second", second.EntityType);

        var third = _service.ReceiveNotification();
        Assert.AreEqual("Third", third.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuesNotification_NotAvailableAgain()
    {
        // Arrange
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act
        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op but should not throw
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);
    }

    [TestMethod]
    public void SendNotification_CreatedAt_IsSetToCurrentTime()
    {
        // Arrange
        var before = System.DateTime.Now;

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var after = System.DateTime.Now;
        var notification = _service.ReceiveNotification();
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // No exception means success
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("System", notification.CreatedBy);
    }
}

