        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Course", "42", EntityOperation.UPDATE, "System");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.IsTrue(notification.Message.Contains("Course (ID: 42)"));
    }

    [TestMethod]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Department 'Engineering' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Instructor", "3", "Jane Doe", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Instructor 'Jane Doe' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdFormat()
    {
        // Arrange & Act
        _service.SendNotification("Student", "99", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DefaultUserName_IsSystem()
    {
        // Arrange & Act
        _service.SendNotification("Course", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleSends_ReturnsFIFOOrder()
    {
        // Arrange
        _service.SendNotification("First", "1", EntityOperation.CREATE);
        _service.SendNotification("Second", "2", EntityOperation.UPDATE);
        _service.SendNotification("Third", "3", EntityOperation.DELETE);

        // Act & Assert
        var first = _service.ReceiveNotification();
        Assert.AreEqual("First", first.EntityType);

        var second = _service.ReceiveNotification();
        Assert.AreEqual("Second", second.EntityType);

        var third = _service.ReceiveNotification();
        Assert.AreEqual("Third", third.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuesNotification_NotAvailableAgain()
    {
        // Arrange
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act
        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op but should not throw
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);
    }

    [TestMethod]
    public void SendNotification_CreatedAt_IsSetToCurrentTime()
    {
        // Arrange
        var before = System.DateTime.Now;

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var after = System.DateTime.Now;
        var notification = _service.ReceiveNotification();
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // No exception means success
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("System", notification.CreatedBy);
    }
}

