using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using System;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new NotificationsController(_context);
        // Drain pre-existing notifications from the static queue
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
        service.Dispose();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void GetNotifications_NoNotifications_ReturnsEmptyList()
    {
        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        // Verify JSON has success=true and count=0
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(successProp);
        Assert.IsNotNull(countProp);
        Assert.AreEqual(true, successProp.GetValue(value));
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - send some notifications via the notification service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        service.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE);
        service.Dispose();

        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(true, successProp.GetValue(value));
        Assert.AreEqual(2, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - send more than 10 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }
        service.Dispose();

        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1) as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }
}

