using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Models;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class SchoolViewModelsTests
{
    [TestMethod]
    public void AssignedCourseData_PropertiesCanBeSet()
    {
        // Arrange & Act
        var data = new AssignedCourseData
        {
            CourseID = 1050,
            Title = "Chemistry",
            Assigned = true
        };

        // Assert
        Assert.AreEqual(1050, data.CourseID);
        Assert.AreEqual("Chemistry", data.Title);
        Assert.IsTrue(data.Assigned);
    }

    [TestMethod]
    public void AssignedCourseData_AssignedDefaultsFalse()
    {
        // Arrange & Act
        var data = new AssignedCourseData();

        // Assert
        Assert.IsFalse(data.Assigned);
    }

    [TestMethod]
    public void EnrollmentDateGroup_PropertiesCanBeSet()
    {
        // Arrange
        var date = new DateTime(2020, 9, 1);

        // Act
        var group = new EnrollmentDateGroup
        {
            EnrollmentDate = date,
            StudentCount = 15
        };

        // Assert
        Assert.AreEqual(date, group.EnrollmentDate);
        Assert.AreEqual(15, group.StudentCount);
    }

    [TestMethod]
    public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
    {
        // Arrange & Act
        var group = new EnrollmentDateGroup { EnrollmentDate = null };

        // Assert
        Assert.IsNull(group.EnrollmentDate);
    }

    [TestMethod]
    public void InstructorIndexData_PropertiesCanBeSet()
    {
        // Arrange
        var instructors = new List<Instructor>
        {
            new Instructor { ID = 1, LastName = "Smith", FirstMidName = "John" }
        };
        var courses = new List<Course>
        {
            new Course { CourseID = 100, Title = "Test" }
        };
        var enrollments = new List<Enrollment>
        {
            new Enrollment { EnrollmentID = 1, Grade = Grade.A }
        };

        // Act
        var viewModel = new InstructorIndexData
        {
            Instructors = instructors,
            Courses = courses,
            Enrollments = enrollments
        };

        // Assert
        Assert.AreEqual(1, viewModel.Instructors.Count());
        Assert.AreEqual(1, viewModel.Courses.Count());
        Assert.AreEqual(1, viewModel.Enrollments.Count());
    }

    [TestMethod]
    public void InstructorIndexData_PropertiesCanBeNull()
    {
        // Arrange & Act
        var viewModel = new InstructorIndexData();

        // Assert
        Assert.IsNull(viewModel.Instructors);
        Assert.IsNull(viewModel.Courses);
        Assert.IsNull(viewModel.Enrollments);
    }
}

