using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Microsoft.EntityFrameworkCore;
using Moq;
using System;
using System.IO;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerFileUploadTests
{
    private SchoolContext _context;
    private CoursesController _controller;
    private Mock<IWebHostEnvironment> _envMock;
    private Mock<ILogger<CoursesController>> _loggerMock;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        var department = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Now };
        _context.Departments.Add(department);
        _context.SaveChanges();
        _context.Courses.Add(new Course { CourseID = 1000, Title = "Existing", Credits = 3, DepartmentID = department.DepartmentID });
        _context.SaveChanges();

        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns((string)null);
        _envMock.Setup(e => e.ContentRootPath).Returns("/fake/content");
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Create_Post_InvalidFileExtension_ReturnsModelError()
    {
        // Arrange
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("document.pdf");
        fileMock.Setup(f => f.Length).Returns(1000);

        var course = new Course
        {
            CourseID = 2000,
            Title = "New Course",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        // Act
        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        // Assert
