+using Microsoft.AspNetCore.Hosting;
+using Microsoft.AspNetCore.Http;
+using Microsoft.Extensions.Logging;
+using Microsoft.EntityFrameworkCore;
+using Moq;
+using System;
+using System.IO;
+using System.Linq;
+
+namespace ContosoUniversity.Tests.Controllers;
+
+[TestClass]
+public sealed class CoursesControllerFileUploadTests
+{
+    private SchoolContext _context;
+    private CoursesController _controller;
+    private Mock<IWebHostEnvironment> _envMock;
+    private Mock<ILogger<CoursesController>> _loggerMock;
+
+    [TestInitialize]
+    public void Setup()
+    {
+        _context = TestDbContextFactory.Create();
+        var department = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Now };
+        _context.Departments.Add(department);
+        _context.SaveChanges();
+        _context.Courses.Add(new Course { CourseID = 1000, Title = "Existing", Credits = 3, DepartmentID = department.DepartmentID });
+        _context.SaveChanges();
+
+        _envMock = new Mock<IWebHostEnvironment>();
+        _envMock.Setup(e => e.WebRootPath).Returns((string)null);
+        _envMock.Setup(e => e.ContentRootPath).Returns("/fake/content");
+        _loggerMock = new Mock<ILogger<CoursesController>>();
+        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
+    }
+
+    [TestCleanup]
+    public void Cleanup()
+    {
+        _controller?.Dispose();
+        _context?.Dispose();
+    }
+
+    [TestMethod]
+    public void Create_Post_InvalidFileExtension_ReturnsModelError()
+    {
+        // Arrange
+        var fileMock = new Mock<IFormFile>();
+        fileMock.Setup(f => f.FileName).Returns("document.pdf");
+        fileMock.Setup(f => f.Length).Returns(1000);
+
+        var course = new Course
+        {
+            CourseID = 2000,
+            Title = "New Course",
+            Credits = 3,
+            DepartmentID = _context.Departments.First().DepartmentID
+        };
+
+        // Act
+        var result = _controller.Create(course, fileMock.Object) as ViewResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+        var errorMessage = _controller.ModelState["teachingMaterialImage"].Errors[0].ErrorMessage;
+        Assert.IsTrue(errorMessage.Contains("valid image file"));
+    }
+
+    [TestMethod]
+    public void Create_Post_FileTooLarge_ReturnsModelError()
+    {
+        // Arrange
+        var fileMock = new Mock<IFormFile>();
+        fileMock.Setup(f => f.FileName).Returns("image.jpg");
+        fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB > 5MB limit
+
+        var course = new Course
+        {
+            CourseID = 2001,
+            Title = "New Course",
+            Credits = 3,
+            DepartmentID = _context.Departments.First().DepartmentID
+        };
+
+        // Act
+        var result = _controller.Create(course, fileMock.Object) as ViewResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+        var errorMessage = _controller.ModelState["teachingMaterialImage"].Errors[0].ErrorMessage;
+        Assert.IsTrue(errorMessage.Contains("5MB"));
+    }
+
+    [TestMethod]
+    [DataRow(".jpg", DisplayName = "JPG extension valid")]
+    [DataRow(".jpeg", DisplayName = "JPEG extension valid")]
+    [DataRow(".png", DisplayName = "PNG extension valid")]
+    [DataRow(".gif", DisplayName = "GIF extension valid")]
+    [DataRow(".bmp", DisplayName = "BMP extension valid")]
+    public void Create_Post_ValidExtension_DoesNotAddExtensionError(string extension)
+    {
+        // Arrange - the file is valid but will fail on disk write (which is expected since we're mocking)
+        var fileMock = new Mock<IFormFile>();
+        fileMock.Setup(f => f.FileName).Returns($"image{extension}");
+        fileMock.Setup(f => f.Length).Returns(1000);
+        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Throws(new IOException("Test - simulated write"));
+
+        var course = new Course
+        {
+            CourseID = 3000,
+            Title = "Course with Image",
+            Credits = 3,
+            DepartmentID = _context.Departments.First().DepartmentID
+        };
+
+        // Act
+        var result = _controller.Create(course, fileMock.Object) as ViewResult;
+
+        // Assert
+        // It should either succeed or fail on file write, but NOT on extension validation
+        if (_controller.ModelState.ContainsKey("teachingMaterialImage"))
+        {
+            var errorMessage = _controller.ModelState["teachingMaterialImage"].Errors[0].ErrorMessage;
+            Assert.IsFalse(errorMessage.Contains("valid image file"),
+                $"Extension {extension} should be accepted but got extension validation error.");
+        }
+    }
+
+    [TestMethod]
+    public void Edit_Post_InvalidFileExtension_ReturnsModelError()
+    {
+        // Arrange
+        var fileMock = new Mock<IFormFile>();
+        fileMock.Setup(f => f.FileName).Returns("document.exe");
+        fileMock.Setup(f => f.Length).Returns(1000);
+
+        var course = new Course
+        {
+            CourseID = 1000,
+            Title = "Existing",
+            Credits = 3,
+            DepartmentID = _context.Departments.First().DepartmentID
+        };
+        // Detach existing entity to avoid tracking conflict
+        var existing = _context.Courses.Find(1000);
+        _context.Entry(existing).State = EntityState.Detached;
+
+        // Act
+        var result = _controller.Edit(course, fileMock.Object) as ViewResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+    }
+
+    [TestMethod]
+    public void Edit_Post_FileTooLarge_ReturnsModelError()
+    {
+        // Arrange
+        var fileMock = new Mock<IFormFile>();
+        fileMock.Setup(f => f.FileName).Returns("big.png");
+        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB > 5MB
+
+        var course = new Course
+        {
+            CourseID = 1000,
+            Title = "Existing",
+            Credits = 3,
+            DepartmentID = _context.Departments.First().DepartmentID
+        };
+        var existing = _context.Courses.Find(1000);
+        _context.Entry(existing).State = EntityState.Detached;
+
+        // Act
+        var result = _controller.Edit(course, fileMock.Object) as ViewResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+        var errorMessage = _controller.ModelState["teachingMaterialImage"].Errors[0].ErrorMessage;
+        Assert.IsTrue(errorMessage.Contains("5MB"));
+    }
+
+    [TestMethod]
+    public void Create_Post_NoFile_SkipsFileValidation()
+    {
+        // Arrange
+        var course = new Course
+        {
+            CourseID = 4000,
+            Title = "No Image Course",
+            Credits = 3,
+            DepartmentID = _context.Departments.First().DepartmentID
+        };
+
+        // Act
+        var result = _controller.Create(course, null) as RedirectToActionResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.AreEqual("Index", result.ActionName);
+        Assert.IsFalse(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+    }
+
+    [TestMethod]
+    public void Edit_Post_NoFile_SkipsFileValidation()
+    {
+        // Arrange
+        var course = new Course
+        {
+            CourseID = 1000,
+            Title = "Updated Title",
+            Credits = 4,
+            DepartmentID = _context.Departments.First().DepartmentID
+        };
+        var existing = _context.Courses.Find(1000);
+        _context.Entry(existing).State = EntityState.Detached;
+
+        // Act
+        var result = _controller.Edit(course, null) as RedirectToActionResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.AreEqual("Index", result.ActionName);
+    }
+
+    [TestMethod]
+    public void Create_Post_ZeroLengthFile_SkipsFileProcessing()
+    {
+        // Arrange
+        var fileMock = new Mock<IFormFile>();
+        fileMock.Setup(f => f.FileName).Returns("empty.jpg");
+        fileMock.Setup(f => f.Length).Returns(0);
+
+        var course = new Course
+        {
+            CourseID = 5000,
+            Title = "Course Empty File",
+            Credits = 3,
+            DepartmentID = _context.Departments.First().DepartmentID
+        };
+
+        // Act - zero length file should be skipped (treated as no file)
+        var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.AreEqual("Index", result.ActionName);
+    }
+}
+

